{"content": "     1|import {
     2|  listAgentEntries,
     3|  resolveAgentDir,
     4|  resolveAgentWorkspaceDir,
     5|  resolveDefaultAgentId,
     6|} from "../agents/agent-scope.js";
     7|import type { AgentIdentityFile } from "../agents/identity-file.js";
     8|import {
     9|  identityHasValues,
    10|  loadAgentIdentityFromWorkspace,
    11|  parseIdentityMarkdown as parseIdentityMarkdownFile,
    12|} from "../agents/identity-file.js";
    13|import { listRouteBindings } from "../config/bindings.js";
    14|import type { OpenClawConfig } from "../config/config.js";
    15|import { normalizeAgentId } from "../routing/session-key.js";
    16|
    17|export type AgentSummary = {
    18|  id: string;
    19|  name?: string;
    20|  identityName?: string;
    21|  identityEmoji?: string;
    22|  identitySource?: "identity" | "config";
    23|  workspace: string;
    24|  agentDir: string;
    25|  model?: string;
    26|  bindings: number;
    27|  bindingDetails?: string[];
    28|  routes?: string[];
    29|  providers?: string[];
    30|  isDefault: boolean;
    31|};
    32|
    33|type AgentEntry = NonNullable<NonNullable<OpenClawConfig["agents"]>["list"]>[number];
    34|
    35|export type AgentIdentity = AgentIdentityFile;
    36|export { listAgentEntries };
    37|
    38|export function findAgentEntryIndex(list: AgentEntry[], agentId: string): number {
    39|  const id = normalizeAgentId(agentId);
    40|  return list.findIndex((entry) => normalizeAgentId(entry.id) === id);
    41|}
    42|
    43|function resolveAgentName(cfg: OpenClawConfig, agentId: string) {
    44|  const entry = listAgentEntries(cfg).find(
    45|    (agent) => normalizeAgentId(agent.id) === normalizeAgentId(agentId),
    46|  );
    47|  return entry?.name?.trim() || undefined;
    48|}
    49|
    50|function resolveAgentModel(cfg: OpenClawConfig, agentId: string) {
    51|  const entry = listAgentEntries(cfg).find(
    52|    (agent) => normalizeAgentId(agent.id) === normalizeAgentId(agentId),
    53|  );
    54|  if (entry?.model) {
    55|    if (typeof entry.model === "string" && entry.model.trim()) {
    56|      return entry.model.trim();
    57|    }
    58|    if (typeof entry.model === "object") {
    59|      const primary = entry.model.primary?.trim();
    60|      if (primary) {
    61|        return primary;
    62|      }
    63|    }
    64|  }
    65|  const raw = cfg.agents?.defaults?.model;
    66|  if (typeof raw === "string") {
    67|    return raw;
    68|  }
    69|  return raw?.primary?.trim() || undefined;
    70|}
    71|
    72|export function parseIdentityMarkdown(content: string): AgentIdentity {
    73|  return parseIdentityMarkdownFile(content);
    74|}
    75|
    76|export function loadAgentIdentity(workspace: string): AgentIdentity | null {
    77|  const parsed = loadAgentIdentityFromWorkspace(workspace);
    78|  if (!parsed) {
    79|    return null;
    80|  }
    81|  return identityHasValues(parsed) ? parsed : null;
    82|}
    83|
    84|export function buildAgentSummaries(cfg: OpenClawConfig): AgentSummary[] {
    85|  const defaultAgentId = normalizeAgentId(resolveDefaultAgentId(cfg));
    86|  const configuredAgents = listAgentEntries(cfg);
    87|  const orderedIds =
    88|    configuredAgents.length > 0
    89|      ? configuredAgents.map((agent) => normalizeAgentId(agent.id))
    90|      : [defaultAgentId];
    91|  const bindingCounts = new Map<string, number>();
    92|  for (const binding of listRouteBindings(cfg)) {
    93|    const agentId = normalizeAgentId(binding.agentId);
    94|    bindingCounts.set(agentId, (bindingCounts.get(agentId) ?? 0) + 1);
    95|  }
    96|
    97|  const ordered = orderedIds.filter((id, index) => orderedIds.indexOf(id) === index);
    98|
    99|  return ordered.map((id) => {
   100|    const workspace = resolveAgentWorkspaceDir(cfg, id);
   101|    const identity = loadAgentIdentity(workspace);
   102|    const configIdentity = configuredAgents.find(
   103|      (agent) => normalizeAgentId(agent.id) === id,
   104|    )?.identity;
   105|    const identityName = identity?.name ?? configIdentity?.name?.trim();
   106|    const identityEmoji = identity?.emoji ?? configIdentity?.emoji?.trim();
   107|    const identitySource = identity
   108|      ? "identity"
   109|      : configIdentity && (identityName || identityEmoji)
   110|        ? "config"
   111|        : undefined;
   112|    return {
   113|      id,
   114|      name: resolveAgentName(cfg, id),
   115|      identityName,
   116|      identityEmoji,
   117|      identitySource,
   118|      workspace,
   119|      agentDir: resolveAgentDir(cfg, id),
   120|      model: resolveAgentModel(cfg, id),
   121|      bindings: bindingCounts.get(id) ?? 0,
   122|      isDefault: id === defaultAgentId,
   123|    };
   124|  });
   125|}
   126|
   127|export function applyAgentConfig(
   128|  cfg: OpenClawConfig,
   129|  params: {
   130|    agentId: string;
   131|    name?: string;
   132|    workspace?: string;
   133|    agentDir?: string;
   134|    model?: string;
   135|  },
   136|): OpenClawConfig {
   137|  const agentId = normalizeAgentId(params.agentId);
   138|  const name = params.name?.trim();
   139|  const list = listAgentEntries(cfg);
   140|  const index = findAgentEntryIndex(list, agentId);
   141|  const base = index >= 0 ? list[index] : { id: agentId };
   142|  const nextEntry: AgentEntry = {
   143|    ...base,
   144|    ...(name ? { name } : {}),
   145|    ...(params.workspace ? { workspace: params.workspace } : {}),
   146|    ...(params.agentDir ? { agentDir: params.agentDir } : {}),
   147|    ...(params.model ? { model: params.model } : {}),
   148|  };
   149|  const nextList = [...list];
   150|  if (index >= 0) {
   151|    nextList[index] = nextEntry;
   152|  } else {
   153|    if (nextList.length === 0 && agentId !== normalizeAgentId(resolveDefaultAgentId(cfg))) {
   154|      nextList.push({ id: resolveDefaultAgentId(cfg) });
   155|    }
   156|    nextList.push(nextEntry);
   157|  }
   158|  return {
   159|    ...cfg,
   160|    agents: {
   161|      ...cfg.agents,
   162|      list: nextList,
   163|    },
   164|  };
   165|}
   166|
   167|export function pruneAgentConfig(
   168|  cfg: OpenClawConfig,
   169|  agentId: string,
   170|): {
   171|  config: OpenClawConfig;
   172|  removedBindings: number;
   173|  removedAllow: number;
   174|} {
   175|  const id = normalizeAgentId(agentId);
   176|  const agents = listAgentEntries(cfg);
   177|  const nextAgentsList = agents.filter((entry) => normalizeAgentId(entry.id) !== id);
   178|  const nextAgents = nextAgentsList.length > 0 ? nextAgentsList : undefined;
   179|
   180|  const bindings = cfg.bindings ?? [];
   181|  const filteredBindings = bindings.filter((binding) => normalizeAgentId(binding.agentId) !== id);
   182|
   183|  const allow = cfg.tools?.agentToAgent?.allow ?? [];
   184|  const filteredAllow = allow.filter((entry) => entry !== id);
   185|
   186|  const nextAgentsConfig = cfg.agents
   187|    ? { ...cfg.agents, list: nextAgents }
   188|    : nextAgents
   189|      ? { list: nextAgents }
   190|      : undefined;
   191|  const nextTools = cfg.tools?.agentToAgent
   192|    ? {
   193|        ...cfg.tools,
   194|        agentToAgent: {
   195|          ...cfg.tools.agentToAgent,
   196|          allow: filteredAllow.length > 0 ? filteredAllow : undefined,
   197|        },
   198|      }
   199|    : cfg.tools;
   200|
   201|  return {
   202|    config: {
   203|      ...cfg,
   204|      agents: nextAgentsConfig,
   205|      bindings: filteredBindings.length > 0 ? filteredBindings : undefined,
   206|      tools: nextTools,
   207|    },
   208|    removedBindings: bindings.length - filteredBindings.length,
   209|    removedAllow: allow.length - filteredAllow.length,
   210|  };
   211|}
