{"content": "     1|import type { OpenClawConfig, HumanDelayConfig, IdentityConfig } from "../config/config.js";
     2|import { resolveAgentConfig } from "./agent-scope.js";
     3|
     4|const DEFAULT_ACK_REACTION = "👀";
     5|
     6|export function resolveAgentIdentity(
     7|  cfg: OpenClawConfig,
     8|  agentId: string,
     9|): IdentityConfig | undefined {
    10|  return resolveAgentConfig(cfg, agentId)?.identity;
    11|}
    12|
    13|export function resolveAckReaction(
    14|  cfg: OpenClawConfig,
    15|  agentId: string,
    16|  opts?: { channel?: string; accountId?: string },
    17|): string {
    18|  // L1: Channel account level
    19|  if (opts?.channel && opts?.accountId) {
    20|    const channelCfg = getChannelConfig(cfg, opts.channel);
    21|    const accounts = channelCfg?.accounts as Record<string, Record<string, unknown>> | undefined;
    22|    const accountReaction = accounts?.[opts.accountId]?.ackReaction as string | undefined;
    23|    if (accountReaction !== undefined) {
    24|      return accountReaction.trim();
    25|    }
    26|  }
    27|
    28|  // L2: Channel level
    29|  if (opts?.channel) {
    30|    const channelCfg = getChannelConfig(cfg, opts.channel);
    31|    const channelReaction = channelCfg?.ackReaction as string | undefined;
    32|    if (channelReaction !== undefined) {
    33|      return channelReaction.trim();
    34|    }
    35|  }
    36|
    37|  // L3: Global messages level
    38|  const configured = cfg.messages?.ackReaction;
    39|  if (configured !== undefined) {
    40|    return configured.trim();
    41|  }
    42|
    43|  // L4: Agent identity emoji fallback
    44|  const emoji = resolveAgentIdentity(cfg, agentId)?.emoji?.trim();
    45|  return emoji || DEFAULT_ACK_REACTION;
    46|}
    47|
    48|export function resolveIdentityNamePrefix(
    49|  cfg: OpenClawConfig,
    50|  agentId: string,
    51|): string | undefined {
    52|  const name = resolveAgentIdentity(cfg, agentId)?.name?.trim();
    53|  if (!name) {
    54|    return undefined;
    55|  }
    56|  return `[${name}]`;
    57|}
    58|
    59|/** Returns just the identity name (without brackets) for template context. */
    60|export function resolveIdentityName(cfg: OpenClawConfig, agentId: string): string | undefined {
    61|  return resolveAgentIdentity(cfg, agentId)?.name?.trim() || undefined;
    62|}
    63|
    64|export function resolveMessagePrefix(
    65|  cfg: OpenClawConfig,
    66|  agentId: string,
    67|  opts?: { configured?: string; hasAllowFrom?: boolean; fallback?: string },
    68|): string {
    69|  const configured = opts?.configured ?? cfg.messages?.messagePrefix;
    70|  if (configured !== undefined) {
    71|    return configured;
    72|  }
    73|
    74|  const hasAllowFrom = opts?.hasAllowFrom === true;
    75|  if (hasAllowFrom) {
    76|    return "";
    77|  }
    78|
    79|  return resolveIdentityNamePrefix(cfg, agentId) ?? opts?.fallback ?? "[openclaw]";
    80|}
    81|
    82|/** Helper to extract a channel config value by dynamic key. */
    83|function getChannelConfig(
    84|  cfg: OpenClawConfig,
    85|  channel: string,
    86|): Record<string, unknown> | undefined {
    87|  const channels = cfg.channels as Record<string, unknown> | undefined;
    88|  const value = channels?.[channel];
    89|  return typeof value === "object" && value !== null
    90|    ? (value as Record<string, unknown>)
    91|    : undefined;
    92|}
    93|
    94|export function resolveResponsePrefix(
    95|  cfg: OpenClawConfig,
    96|  agentId: string,
    97|  opts?: { channel?: string; accountId?: string },
    98|): string | undefined {
    99|  // L1: Channel account level
   100|  if (opts?.channel && opts?.accountId) {
   101|    const channelCfg = getChannelConfig(cfg, opts.channel);
   102|    const accounts = channelCfg?.accounts as Record<string, Record<string, unknown>> | undefined;
   103|    const accountPrefix = accounts?.[opts.accountId]?.responsePrefix as string | undefined;
   104|    if (accountPrefix !== undefined) {
   105|      if (accountPrefix === "auto") {
   106|        return resolveIdentityNamePrefix(cfg, agentId);
   107|      }
   108|      return accountPrefix;
   109|    }
   110|  }
   111|
   112|  // L2: Channel level
   113|  if (opts?.channel) {
   114|    const channelCfg = getChannelConfig(cfg, opts.channel);
   115|    const channelPrefix = channelCfg?.responsePrefix as string | undefined;
   116|    if (channelPrefix !== undefined) {
   117|      if (channelPrefix === "auto") {
   118|        return resolveIdentityNamePrefix(cfg, agentId);
   119|      }
   120|      return channelPrefix;
   121|    }
   122|  }
   123|
   124|  // L4: Global level
   125|  const configured = cfg.messages?.responsePrefix;
   126|  if (configured !== undefined) {
   127|    if (configured === "auto") {
   128|      return resolveIdentityNamePrefix(cfg, agentId);
   129|    }
   130|    return configured;
   131|  }
   132|  return undefined;
   133|}
   134|
   135|export function resolveEffectiveMessagesConfig(
   136|  cfg: OpenClawConfig,
   137|  agentId: string,
   138|  opts?: {
   139|    hasAllowFrom?: boolean;
   140|    fallbackMessagePrefix?: string;
   141|    channel?: string;
   142|    accountId?: string;
   143|  },
   144|): { messagePrefix: string; responsePrefix?: string } {
   145|  return {
   146|    messagePrefix: resolveMessagePrefix(cfg, agentId, {
   147|      hasAllowFrom: opts?.hasAllowFrom,
   148|      fallback: opts?.fallbackMessagePrefix,
   149|    }),
   150|    responsePrefix: resolveResponsePrefix(cfg, agentId, {
   151|      channel: opts?.channel,
   152|      accountId: opts?.accountId,
   153|    }),
   154|  };
   155|}
   156|
   157|export function resolveHumanDelayConfig(
   158|  cfg: OpenClawConfig,
   159|  agentId: string,
   160|): HumanDelayConfig | undefined {
   161|  const defaults = cfg.agents?.defaults?.humanDelay;
   162|  const overrides = resolveAgentConfig(cfg, agentId)?.humanDelay;
   163|  if (!defaults && !overrides) {
   164|    return undefined;
   165|  }
   166|  return {
   167|    mode: overrides?.mode ?? defaults?.mode,
   168|    minMs: overrides?.minMs ?? defaults?.minMs,
   169|    maxMs: overrides?.maxMs ?? defaults?.maxMs,
   170|  };
   171|}
