{"content": "     1|import { describe, expect, it } from "vitest";
     2|import { parseIdentityMarkdown } from "./identity-file.js";
     3|
     4|describe("parseIdentityMarkdown", () => {
     5|  it("ignores identity template placeholders", () => {
     6|    const content = `
     7|# IDENTITY.md - Who Am I?
     8|
     9|- **Name:** *(pick something you like)*
    10|- **Creature:** *(AI? robot? familiar? ghost in the machine? something weirder?)*
    11|- **Vibe:** *(how do you come across? sharp? warm? chaotic? calm?)*
    12|- **Emoji:** *(your signature - pick one that feels right)*
    13|- **Avatar:** *(workspace-relative path, http(s) URL, or data URI)*
    14|`;
    15|    const parsed = parseIdentityMarkdown(content);
    16|    expect(parsed).toEqual({});
    17|  });
    18|
    19|  it("parses explicit identity values", () => {
    20|    const content = `
    21|- **Name:** Samantha
    22|- **Creature:** Robot
    23|- **Vibe:** Warm
    24|- **Emoji:** :robot:
    25|- **Avatar:** avatars/openclaw.png
    26|`;
    27|    const parsed = parseIdentityMarkdown(content);
    28|    expect(parsed).toEqual({
    29|      name: "Samantha",
    30|      creature: "Robot",
    31|      vibe: "Warm",
    32|      emoji: ":robot:",
    33|      avatar: "avatars/openclaw.png",
    34|    });
    35|  });
    36|
    37|  describe("capabilities parsing", () => {
    38|    it("parses comma-separated capabilities", () => {
    39|      const content = "- name: TestBot\n- capabilities: code, testing, ui";
    40|      const parsed = parseIdentityMarkdown(content);
    41|      expect(parsed.capabilities).toEqual(["code", "testing", "ui"]);
    42|    });
    43|
    44|    it("parses single capability", () => {
    45|      const content = "- capabilities: code";
    46|      const parsed = parseIdentityMarkdown(content);
    47|      expect(parsed.capabilities).toEqual(["code"]);
    48|    });
    49|
    50|    it("returns undefined capabilities when no capabilities line present", () => {
    51|      const content = "- name: TestBot";
    52|      const parsed = parseIdentityMarkdown(content);
    53|      expect(parsed.capabilities).toBeUndefined();
    54|    });
    55|
    56|    it("returns undefined capabilities when capabilities value is empty", () => {
    57|      const content = "- capabilities: ";
    58|      const parsed = parseIdentityMarkdown(content);
    59|      expect(parsed.capabilities).toBeUndefined();
    60|    });
    61|
    62|    it("parses capabilities alongside other fields", () => {
    63|      const content = `- name: TestBot
    64|- emoji: :robot:
    65|- capabilities: code, testing
    66|- vibe: chill`;
    67|      const parsed = parseIdentityMarkdown(content);
    68|      expect(parsed.name).toBe("TestBot");
    69|      expect(parsed.emoji).toBe(":robot:");
    70|      expect(parsed.capabilities).toEqual(["code", "testing"]);
    71|      expect(parsed.vibe).toBe("chill");
    72|    });
    73|  });
    74|});
