{"content": "     1|import fs from "node:fs";
     2|import path from "node:path";
     3|import type { OpenClawConfig } from "../config/config.js";
     4|import { resolveAgentModelFallbackValues } from "../config/model-input.js";
     5|import { resolveStateDir } from "../config/paths.js";
     6|import { createSubsystemLogger } from "../logging/subsystem.js";
     7|import {
     8|  DEFAULT_AGENT_ID,
     9|  normalizeAgentId,
    10|  parseAgentSessionKey,
    11|  resolveAgentIdFromSessionKey,
    12|} from "../routing/session-key.js";
    13|import { resolveUserPath } from "../utils.js";
    14|import { normalizeSkillFilter } from "./skills/filter.js";
    15|import { resolveDefaultAgentWorkspaceDir } from "./workspace.js";
    16|
    17|let log: ReturnType<typeof createSubsystemLogger> | null = null;
    18|
    19|function getLog(): ReturnType<typeof createSubsystemLogger> {
    20|  log ??= createSubsystemLogger("agent-scope");
    21|  return log;
    22|}
    23|
    24|/** Strip null bytes from paths to prevent ENOTDIR errors. */
    25|function stripNullBytes(s: string): string {
    26|  // eslint-disable-next-line no-control-regex
    27|  return s.replace(/\0/g, "");
    28|}
    29|
    30|export { resolveAgentIdFromSessionKey };
    31|
    32|type AgentEntry = NonNullable<NonNullable<OpenClawConfig["agents"]>["list"]>[number];
    33|
    34|type ResolvedAgentConfig = {
    35|  name?: string;
    36|  workspace?: string;
    37|  agentDir?: string;
    38|  model?: AgentEntry["model"];
    39|  thinkingDefault?: AgentEntry["thinkingDefault"];
    40|  reasoningDefault?: AgentEntry["reasoningDefault"];
    41|  fastModeDefault?: AgentEntry["fastModeDefault"];
    42|  skills?: AgentEntry["skills"];
    43|  memorySearch?: AgentEntry["memorySearch"];
    44|  humanDelay?: AgentEntry["humanDelay"];
    45|  heartbeat?: AgentEntry["heartbeat"];
    46|  identity?: AgentEntry["identity"];
    47|  groupChat?: AgentEntry["groupChat"];
    48|  subagents?: AgentEntry["subagents"];
    49|  sandbox?: AgentEntry["sandbox"];
    50|  tools?: AgentEntry["tools"];
    51|};
    52|
    53|let defaultAgentWarned = false;
    54|
    55|export function listAgentEntries(cfg: OpenClawConfig): AgentEntry[] {
    56|  const list = cfg.agents?.list;
    57|  if (!Array.isArray(list)) {
    58|    return [];
    59|  }
    60|  return list.filter((entry): entry is AgentEntry => Boolean(entry && typeof entry === "object"));
    61|}
    62|
    63|export function listAgentIds(cfg: OpenClawConfig): string[] {
    64|  const agents = listAgentEntries(cfg);
    65|  if (agents.length === 0) {
    66|    return [DEFAULT_AGENT_ID];
    67|  }
    68|  const seen = new Set<string>();
    69|  const ids: string[] = [];
    70|  for (const entry of agents) {
    71|    const id = normalizeAgentId(entry?.id);
    72|    if (seen.has(id)) {
    73|      continue;
    74|    }
    75|    seen.add(id);
    76|    ids.push(id);
    77|  }
    78|  return ids.length > 0 ? ids : [DEFAULT_AGENT_ID];
    79|}
    80|
    81|export function resolveDefaultAgentId(cfg: OpenClawConfig): string {
    82|  const agents = listAgentEntries(cfg);
    83|  if (agents.length === 0) {
    84|    return DEFAULT_AGENT_ID;
    85|  }
    86|  const defaults = agents.filter((agent) => agent?.default);
    87|  if (defaults.length > 1 && !defaultAgentWarned) {
    88|    defaultAgentWarned = true;
    89|    getLog().warn("Multiple agents marked default=true; using the first entry as default.");
    90|  }
    91|  const chosen = (defaults[0] ?? agents[0])?.id?.trim();
    92|  return normalizeAgentId(chosen || DEFAULT_AGENT_ID);
    93|}
    94|
    95|export function resolveSessionAgentIds(params: {
    96|  sessionKey?: string;
    97|  config?: OpenClawConfig;
    98|  agentId?: string;
    99|}): {
   100|  defaultAgentId: string;
   101|  sessionAgentId: string;
   102|} {
   103|  const defaultAgentId = resolveDefaultAgentId(params.config ?? {});
   104|  const explicitAgentIdRaw =
   105|    typeof params.agentId === "string" ? params.agentId.trim().toLowerCase() : "";
   106|  const explicitAgentId = explicitAgentIdRaw ? normalizeAgentId(explicitAgentIdRaw) : null;
   107|  const sessionKey = params.sessionKey?.trim();
   108|  const normalizedSessionKey = sessionKey ? sessionKey.toLowerCase() : undefined;
   109|  const parsed = normalizedSessionKey ? parseAgentSessionKey(normalizedSessionKey) : null;
   110|  const sessionAgentId =
   111|    explicitAgentId ?? (parsed?.agentId ? normalizeAgentId(parsed.agentId) : defaultAgentId);
   112|  return { defaultAgentId, sessionAgentId };
   113|}
   114|
   115|export function resolveSessionAgentId(params: {
   116|  sessionKey?: string;
   117|  config?: OpenClawConfig;
   118|}): string {
   119|  return resolveSessionAgentIds(params).sessionAgentId;
   120|}
   121|
   122|function resolveAgentEntry(cfg: OpenClawConfig, agentId: string): AgentEntry | undefined {
   123|  const id = normalizeAgentId(agentId);
   124|  return listAgentEntries(cfg).find((entry) => normalizeAgentId(entry.id) === id);
   125|}
   126|
   127|export function resolveAgentConfig(
   128|  cfg: OpenClawConfig,
   129|  agentId: string,
   130|): ResolvedAgentConfig | undefined {
   131|  const id = normalizeAgentId(agentId);
   132|  const entry = resolveAgentEntry(cfg, id);
   133|  if (!entry) {
   134|    return undefined;
   135|  }
   136|  return {
   137|    name: typeof entry.name === "string" ? entry.name : undefined,
   138|    workspace: typeof entry.workspace === "string" ? entry.workspace : undefined,
   139|    agentDir: typeof entry.agentDir === "string" ? entry.agentDir : undefined,
   140|    model:
   141|      typeof entry.model === "string" || (entry.model && typeof entry.model === "object")
   142|        ? entry.model
   143|        : undefined,
   144|    thinkingDefault: entry.thinkingDefault,
   145|    reasoningDefault: entry.reasoningDefault,
   146|    fastModeDefault: entry.fastModeDefault,
   147|    skills: Array.isArray(entry.skills) ? entry.skills : undefined,
