{"content": "     1|import path from "node:path";
     2|import { resolveUserPath } from "../utils.js";
     3|
     4|export function normalizeWorkspaceDir(workspaceDir?: string): string | null {
     5|  const trimmed = workspaceDir?.trim();
     6|  if (!trimmed) {
     7|    return null;
     8|  }
     9|  const expanded = trimmed.startsWith("~") ? resolveUserPath(trimmed) : trimmed;
    10|  const resolved = path.resolve(expanded);
    11|  // Refuse filesystem roots as "workspace" (too broad; almost always a bug).
    12|  if (resolved === path.parse(resolved).root) {
    13|    return null;
    14|  }
    15|  return resolved;
    16|}
    17|
    18|export function resolveWorkspaceRoot(workspaceDir?: string): string {
    19|  return normalizeWorkspaceDir(workspaceDir) ?? process.cwd();
