{"content": "     1|import { z } from "zod";
     2|import { AgentDefaultsSchema } from "./zod-schema.agent-defaults.js";
     3|import { AgentEntrySchema } from "./zod-schema.agent-runtime.js";
     4|import { TranscribeAudioSchema } from "./zod-schema.core.js";
     5|
     6|export const AgentsSchema = z
     7|  .object({
     8|    defaults: z.lazy(() => AgentDefaultsSchema).optional(),
     9|    list: z.array(AgentEntrySchema).optional(),
    10|  })
    11|  .strict()
    12|  .optional();
    13|
    14|const BindingMatchSchema = z
    15|  .object({
    16|    channel: z.string(),
    17|    accountId: z.string().optional(),
    18|    peer: z
    19|      .object({
    20|        kind: z.union([
    21|          z.literal("direct"),
    22|          z.literal("group"),
    23|          z.literal("channel"),
    24|          /** @deprecated Use `direct` instead. Kept for backward compatibility. */
    25|          z.literal("dm"),
    26|        ]),
    27|        id: z.string(),
    28|      })
    29|      .strict()
    30|      .optional(),
    31|    guildId: z.string().optional(),
    32|    teamId: z.string().optional(),
    33|    roles: z.array(z.string()).optional(),
    34|  })
    35|  .strict();
    36|
    37|const RouteBindingSchema = z
    38|  .object({
    39|    type: z.literal("route").optional(),
    40|    agentId: z.string(),
    41|    comment: z.string().optional(),
    42|    match: BindingMatchSchema,
    43|  })
    44|  .strict();
    45|
    46|const AcpBindingSchema = z
    47|  .object({
    48|    type: z.literal("acp"),
    49|    agentId: z.string(),
    50|    comment: z.string().optional(),
    51|    match: BindingMatchSchema,
    52|    acp: z
    53|      .object({
    54|        mode: z.enum(["persistent", "oneshot"]).optional(),
    55|        label: z.string().optional(),
    56|        cwd: z.string().optional(),
    57|        backend: z.string().optional(),
    58|      })
    59|      .strict()
    60|      .optional(),
    61|  })
    62|  .strict()
    63|  .superRefine((value, ctx) => {
    64|    const peerId = value.match.peer?.id?.trim() ?? "";
    65|    if (!peerId) {
    66|      ctx.addIssue({
    67|        code: z.ZodIssueCode.custom,
    68|        path: ["match", "peer"],
    69|        message: "ACP bindings require match.peer.id to target a concrete conversation.",
    70|      });
    71|      return;
    72|    }
    73|    const channel = value.match.channel.trim().toLowerCase();
    74|    if (channel !== "discord" && channel !== "telegram" && channel !== "feishu") {
    75|      ctx.addIssue({
    76|        code: z.ZodIssueCode.custom,
    77|        path: ["match", "channel"],
    78|        message:
    79|          'ACP bindings currently support only "discord", "telegram", and "feishu" channels.',
    80|      });
    81|      return;
    82|    }
    83|    if (channel === "telegram" && !/^-\d+:topic:\d+$/.test(peerId)) {
    84|      ctx.addIssue({
    85|        code: z.ZodIssueCode.custom,
    86|        path: ["match", "peer", "id"],
    87|        message:
    88|          "Telegram ACP bindings require canonical topic IDs in the form -1001234567890:topic:42.",
    89|      });
    90|    }
    91|    if (channel === "feishu") {
    92|      const peerKind = value.match.peer?.kind;
    93|      const isDirectId =
    94|        (peerKind === "direct" || peerKind === "dm") &&
    95|        /^[^:]+$/.test(peerId) &&
    96|        !peerId.startsWith("oc_") &&
    97|        !peerId.startsWith("on_");
    98|      const isTopicId =
    99|        peerKind === "group" && /^oc_[^:]+:topic:[^:]+(?::sender:ou_[^:]+)?$/.test(peerId);
   100|      if (!isDirectId && !isTopicId) {
   101|        ctx.addIssue({
   102|          code: z.ZodIssueCode.custom,
   103|          path: ["match", "peer", "id"],
   104|          message:
   105|            "Feishu ACP bindings require direct peer IDs for DMs or topic IDs in the form oc_group:topic:om_root[:sender:ou_xxx].",
   106|        });
   107|      }
   108|    }
   109|  });
   110|
   111|export const BindingsSchema = z.array(z.union([RouteBindingSchema, AcpBindingSchema])).optional();
   112|
   113|export const BroadcastStrategySchema = z.enum(["parallel", "sequential"]);
   114|
   115|export const BroadcastSchema = z
   116|  .object({
   117|    strategy: BroadcastStrategySchema.optional(),
   118|  })
   119|  .catchall(z.array(z.string()))
   120|  .optional();
   121|
   122|export const AudioSchema = z
   123|  .object({
   124|    transcription: TranscribeAudioSchema,
   125|  })
   126|  .strict()
   127|  .optional();
