     2|  expandToolGroups,
     3|  normalizeToolList,
     4|  normalizeToolName,
     5|  resolveToolProfilePolicy,
     6|  TOOL_GROUPS,
     7|} from "./tool-policy-shared.js";
     8|import type { AnyAgentTool } from "./tools/common.js";
     9|export {
    10|  expandToolGroups,
    11|  normalizeToolList,
    12|  normalizeToolName,
    13|  resolveToolProfilePolicy,
    14|  TOOL_GROUPS,
    15|} from "./tool-policy-shared.js";
    16|export type { ToolProfileId } from "./tool-policy-shared.js";
    17|
    18|// Keep tool-policy browser-safe: do not import tools/common at runtime.
    19|function wrapOwnerOnlyToolExecution(tool: AnyAgentTool, senderIsOwner: boolean): AnyAgentTool {
    20|  if (tool.ownerOnly !== true || senderIsOwner || !tool.execute) {
    21|    return tool;
    22|  }
    23|  return {
    24|    ...tool,
    25|    execute: async () => {
    26|      throw new Error("Tool restricted to owner senders.");
    27|    },
    28|  };
    29|}
    30|
    31|const OWNER_ONLY_TOOL_NAME_FALLBACKS = new Set<string>([
    32|  "whatsapp_login",
    33|  "cron",
    34|  "gateway",
    35|  "nodes",
    36|]);
    37|
    38|export function isOwnerOnlyToolName(name: string) {
    39|  return OWNER_ONLY_TOOL_NAME_FALLBACKS.has(normalizeToolName(name));
    40|}
    41|
    42|function isOwnerOnlyTool(tool: AnyAgentTool) {
    43|  return tool.ownerOnly === true || isOwnerOnlyToolName(tool.name);
    44|}
    45|
    46|export function applyOwnerOnlyToolPolicy(tools: AnyAgentTool[], senderIsOwner: boolean) {
    47|  const withGuard = tools.map((tool) => {
    48|    if (!isOwnerOnlyTool(tool)) {
    49|      return tool;
    50|    }
    51|    return wrapOwnerOnlyToolExecution(tool, senderIsOwner);
    52|  });
    53|  if (senderIsOwner) {
    54|    return withGuard;
    55|  }
    56|  return withGuard.filter((tool) => !isOwnerOnlyTool(tool));
    57|}
    58|
    59|export type ToolPolicyLike = {
    60|  allow?: string[];
    61|  deny?: string[];
    62|};
    63|
    64|export type PluginToolGroups = {
    65|  all: string[];
    66|  byPlugin: Map<string, string[]>;
    67|};
    68|
    69|export type AllowlistResolution = {
    70|  policy: ToolPolicyLike | undefined;
    71|  unknownAllowlist: string[];
    72|  strippedAllowlist: boolean;
    73|};
    74|
    75|export function collectExplicitAllowlist(policies: Array<ToolPolicyLike | undefined>): string[] {
    76|  const entries: string[] = [];
    77|  for (const policy of policies) {
    78|    if (!policy?.allow) {
    79|      continue;
    80|    }
    81|    for (const value of policy.allow) {
    82|      if (typeof value !== "string") {
    83|        continue;
    84|      }
    85|      const trimmed = value.trim();
    86|      if (trimmed) {
    87|        entries.push(trimmed);
    88|      }
    89|    }
    90|  }
    91|  return entries;
    92|}
    93|
    94|export function buildPluginToolGroups<T extends { name: string }>(params: {
    95|  tools: T[];
    96|  toolMeta: (tool: T) => { pluginId: string } | undefined;
    97|}): PluginToolGroups {
    98|  const all: string[] = [];
    99|  const byPlugin = new Map<string, string[]>();
   100|  for (const tool of params.tools) {
   101|    const meta = params.toolMeta(tool);
   102|    if (!meta) {
   103|      continue;
   104|    }
   105|    const name = normalizeToolName(tool.name);
   106|    all.push(name);
   107|    const pluginId = meta.pluginId.toLowerCase();
   108|    const list = byPlugin.get(pluginId) ?? [];
   109|    list.push(name);
   110|    byPlugin.set(pluginId, list);
   111|  }
   112|  return { all, byPlugin };
   113|}
   114|
   115|export function expandPluginGroups(
   116|  list: string[] | undefined,
   117|  groups: PluginToolGroups,
   118|): string[] | undefined {
   119|  if (!list || list.length === 0) {
   120|    return list;
   121|  }
   122|  const expanded: string[] = [];
   123|  for (const entry of list) {
   124|    const normalized = normalizeToolName(entry);
   125|    if (normalized === "group:plugins") {
   126|      if (groups.all.length > 0) {
   127|        expanded.push(...groups.all);
   128|      } else {
   129|        expanded.push(normalized);
   130|      }
   131|      continue;
   132|    }
   133|    const tools = groups.byPlugin.get(normalized);
   134|    if (tools && tools.length > 0) {
   135|      expanded.push(...tools);
   136|      continue;
   137|    }
   138|    expanded.push(normalized);
   139|  }
   140|  return Array.from(new Set(expanded));
   141|}
   142|
   143|export function expandPolicyWithPluginGroups(
   144|  policy: ToolPolicyLike | undefined,
   145|  groups: PluginToolGroups,
   146|): ToolPolicyLike | undefined {
   147|  if (!policy) {
   148|    return undefined;
   149|  }
   150|  return {
   151|    allow: expandPluginGroups(policy.allow, groups),
   152|    deny: expandPluginGroups(policy.deny, groups),
   153|  };
   154|}
   155|
   156|export function stripPluginOnlyAllowlist(
   157|  policy: ToolPolicyLike | undefined,
   158|  groups: PluginToolGroups,
   159|  coreTools: Set<string>,
   160|): AllowlistResolution {
   161|  if (!policy?.allow || policy.allow.length === 0) {
   162|    return { policy, unknownAllowlist: [], strippedAllowlist: false };
   163|  }
   164|  const normalized = normalizeToolList(policy.allow);
   165|  if (normalized.length === 0) {
   166|    return { policy, unknownAllowlist: [], strippedAllowlist: false };
   167|  }
   168|  const pluginIds = new Set(groups.byPlugin.keys());
   169|  const pluginTools = new Set(groups.all);
   170|  const unknownAllowlist: string[] = [];
   171|  let hasCoreEntry = false;
   172|  for (const entry of normalized) {
   173|    if (entry === "*") {
   174|      hasCoreEntry = true;
   175|      continue;
   176|    }
   177|    const isPluginEntry =
   178|      entry === "group:plugins" || pluginIds.has(entry) || pluginTools.has(entry);
   179|    const expanded = expandToolGroups([entry]);
   180|    const isCoreEntry = expanded.some((tool) => coreTools.has(tool));
   181|    if (isCoreEntry) {
   182|      hasCoreEntry = true;
   183|    }
   184|    if (!isCoreEntry && !isPluginEntry) {
   185|      unknownAllowlist.push(entry);
   186|    }
   187|  }
   188|  const strippedAllowlist = !hasCoreEntry;
   189|  // When an allowlist contains only plugin tools, we strip it to avoid accidentally
   190|  // disabling core tools. Users who want additive behavior should prefer `tools.alsoAllow`.
   191|  if (strippedAllowlist) {
   192|    // Note: logging happens in the caller (pi-tools/tools-invoke) after this function returns.
   193|    // We keep this note here for future maintainers.
   194|  }
   195|  return {
   196|    policy: strippedAllowlist ? { ...policy, allow: undefined } : policy,
   197|    unknownAllowlist: Array.from(new Set(unknownAllowlist)),
   198|    strippedAllowlist,
   199|  };
   200|}
   201|
   202|export function mergeAlsoAllowPolicy<TPolicy extends { allow?: string[] }>(
   203|  policy: TPolicy | undefined,
   204|  alsoAllow?: string[],
   205|): TPolicy | undefined {
   206|  if (!policy?.allow || !Array.isArray(alsoAllow) || alsoAllow.length === 0) {
   207|    return policy;
   208|  }
   209|  return { ...policy, allow: Array.from(new Set([...policy.allow, ...alsoAllow])) };
   210|}
