     4|
     5|export type AgentIdentityFile = {
     6|  name?: string;
     7|  emoji?: string;
     8|  theme?: string;
     9|  creature?: string;
    10|  vibe?: string;
    11|  avatar?: string;
    12|  capabilities?: string[];
    13|};
    14|
    15|const IDENTITY_PLACEHOLDER_VALUES = new Set([
    16|  "pick something you like",
    17|  "ai? robot? familiar? ghost in the machine? something weirder?",
    18|  "how do you come across? sharp? warm? chaotic? calm?",
    19|  "your signature - pick one that feels right",
    20|  "workspace-relative path, http(s) url, or data uri",
    21|]);
    22|
    23|function normalizeIdentityValue(value: string): string {
    24|  let normalized = value.trim();
    25|  normalized = normalized.replace(/^[*_]+|[*_]+$/g, "").trim();
    26|  if (normalized.startsWith("(") && normalized.endsWith(")")) {
    27|    normalized = normalized.slice(1, -1).trim();
    28|  }
    29|  normalized = normalized.replace(/[\u2013\u2014]/g, "-");
    30|  normalized = normalized.replace(/\s+/g, " ").toLowerCase();
    31|  return normalized;
    32|}
    33|
    34|function isIdentityPlaceholder(value: string): boolean {
    35|  const normalized = normalizeIdentityValue(value);
    36|  return IDENTITY_PLACEHOLDER_VALUES.has(normalized);
    37|}
    38|
    39|export function parseIdentityMarkdown(content: string): AgentIdentityFile {
    40|  const identity: AgentIdentityFile = {};
    41|  const lines = content.split(/\r?\n/);
    42|  for (const line of lines) {
    43|    const cleaned = line.trim().replace(/^\s*-\s*/, "");
    44|    const colonIndex = cleaned.indexOf(":");
    45|    if (colonIndex === -1) {
    46|      continue;
    47|    }
    48|    const label = cleaned.slice(0, colonIndex).replace(/[*_]/g, "").trim().toLowerCase();
    49|    const value = cleaned
    50|      .slice(colonIndex + 1)
    51|      .replace(/^[*_]+|[*_]+$/g, "")
    52|      .trim();
    53|    if (!value) {
    54|      continue;
    55|    }
    56|    if (isIdentityPlaceholder(value)) {
    57|      continue;
    58|    }
    59|    if (label === "name") {
    60|      identity.name = value;
    61|    }
    62|    if (label === "emoji") {
    63|      identity.emoji = value;
    64|    }
    65|    if (label === "creature") {
    66|      identity.creature = value;
    67|    }
    68|    if (label === "vibe") {
    69|      identity.vibe = value;
    70|    }
    71|    if (label === "theme") {
    72|      identity.theme = value;
    73|    }
    74|    if (label === "avatar") {
    75|      identity.avatar = value;
    76|    }
    77|    if (label === "capabilities") {
    78|      const caps = value
    79|        .split(",")
    80|        .map((s) => s.trim())
    81|        .filter(Boolean);
    82|      if (caps.length > 0) {
    83|        identity.capabilities = caps;
    84|      }
    85|    }
    86|  }
    87|  return identity;
    88|}
    89|
    90|export function identityHasValues(identity: AgentIdentityFile): boolean {
    91|  return Boolean(
    92|    identity.name ||
    93|    identity.emoji ||
    94|    identity.theme ||
    95|    identity.creature ||
    96|    identity.vibe ||
    97|    identity.avatar,
    98|  );
    99|}
   100|
   101|export function loadIdentityFromFile(identityPath: string): AgentIdentityFile | null {
   102|  try {
   103|    const content = fs.readFileSync(identityPath, "utf-8");
   104|    const parsed = parseIdentityMarkdown(content);
   105|    if (!identityHasValues(parsed)) {
   106|      return null;
   107|    }
   108|    return parsed;
   109|  } catch {
   110|    return null;
   111|  }
   112|}
