    10|export function normalizeSkillFilterForComparison(
    11|  skillFilter?: ReadonlyArray<unknown>,
    12|): string[] | undefined {
    13|  const normalized = normalizeSkillFilter(skillFilter);
    14|  if (normalized === undefined) {
    15|    return undefined;
    16|  }
    17|  return Array.from(new Set(normalized)).toSorted();
    18|}
    19|
    20|export function matchesSkillFilter(
    21|  cached?: ReadonlyArray<unknown>,
    22|  next?: ReadonlyArray<unknown>,
    23|): boolean {
    24|  const cachedNormalized = normalizeSkillFilterForComparison(cached);
    25|  const nextNormalized = normalizeSkillFilterForComparison(next);
    26|  if (cachedNormalized === undefined || nextNormalized === undefined) {
    27|    return cachedNormalized === nextNormalized;
    28|  }
    29|  if (cachedNormalized.length !== nextNormalized.length) {
    30|    return false;
    31|  }
    32|  return cachedNormalized.every((entry, index) => entry === nextNormalized[index]);
